// stInitialDrawer builds the Alpine x-data expression for drawer + recovery_mode reactivity.
func stInitialDrawer(vm SalesTaxVM) string {
	open := "false"
	if vm.DrawerOpen {
		open = "true"
	}
	rm := vm.RecoveryMode
	if rm == "" {
		rm = "none"
	}
	return fmt.Sprintf(`{ drawerOpen: %s, recoveryMode: %q }`, open, rm)
}

// stRowClass styles inactive rows.
func stRowClass(tc models.TaxCode) string {
	if !tc.IsActive {
		return "border-b border-border-subtle bg-background text-text-muted2"
	}
	return "border-b border-border-subtle"
}

// stRateDisplay converts the stored fraction (0.050000) to a human-readable percentage string.
// e.g. 0.050000 → "5.00"
func stRateDisplay(rate decimal.Decimal) string {
	pct := rate.Mul(decimal.NewFromInt(100))
	// Use up to 4 decimal places but strip trailing zeros.
	s := pct.StringFixed(4)
	// Trim redundant trailing zeros after decimal point.
	for len(s) > 0 && s[len(s)-1] == '0' {
		s = s[:len(s)-1]
	}
	if len(s) > 0 && s[len(s)-1] == '.' {
		s = s[:len(s)-1]
	}
	return s
}

// stScopeLabel returns a human-readable scope string.
func stScopeLabel(scope models.TaxScope) string {
	switch scope {
	case models.TaxScopeSales:
		return "Sales"
	case models.TaxScopePurchase:
		return "Purchase"
	default:
		return "Sales & Purchase"
	}
}

// stRecoveryLabel returns a short recovery description for the table.
func stRecoveryLabel(tc models.TaxCode) string {
	switch tc.RecoveryMode {
	case models.TaxRecoveryFull:
		return "Full ITC"
	case models.TaxRecoveryPartial:
		return "Partial (" + tc.RecoveryRate.StringFixed(0) + "%)"
	default:
		return "None"
	}
}

